  KangurMobileCard as Card,
  KangurMobileScrollScreen,
  KangurMobileSectionTitle,
  type KangurMobileTone as Tone,
} from '../shared/KangurMobileUi';
import {
  BadgesCard,
  LessonCheckpointsCard,
  LessonMasteryCard,
  LinkButton,
  MessageCard,
  NextStepsCard,
} from './duels-primitives';
import {
  DuelLobbyLeaderboardSection,
  DuelLobbyPresenceSection,
  DuelLobbyRecentOpponentsSection,
  DuelLobbySearchSection,
} from './duels-screen-lobby-secondary-sections';
import { HOME_ROUTE } from './utils/duels-ui';
import { DuelLobbyChatPanel } from './DuelLobbyChatPanel';
import { DuelLobbyPlayPanel } from './DuelLobbyPlayPanel';
import { DuelLobbyRoomsPanel } from './DuelLobbyRoomsPanel';
import { type UseKangurMobileDuelLobbyChatResult as DuelChatState } from './useKangurMobileDuelLobbyChat';
import { type UseKangurMobileDuelsLobbyResult as DuelLobbyState } from './useKangurMobileDuelsLobby';

type DuelCopy = KangurMobileCopy;
type DuelLocale = KangurMobileLocale;

type DuelsLobbyViewProps = {
  activeLearnerId: string | null;
  autoRefreshEnabled: boolean;
  autoRefreshChipLabel: string;
  canSendChatMessage: boolean;
  chat: DuelChatState;
  chatActionError: string | null;
  chatDraft: string;
  chatRemainingChars: number;
  copy: DuelCopy;
  lobby: DuelLobbyState;
  lobbyChatPreview: DuelChatState['messages'];
  loginIntroCallToAction: React.JSX.Element;
  loginStartCallToAction: React.JSX.Element;
  locale: DuelLocale;
  onChatDraftChange: (nextValue: string) => void;
  onOpenSession: (sessionId: string) => void;
  onSendLobbyChat: () => Promise<void>;
  onToggleAutoRefresh: () => void;
  renderJoinAction: (targetSessionId: string) => React.JSX.Element;
  renderSpectateAction: (targetSessionId: string) => React.JSX.Element;
  searchStatusLabel: string;
  searchStatusTone: Tone;
};

function GuestIntroCard({ copy, loginIntroCallToAction }: { copy: DuelCopy, loginIntroCallToAction: React.JSX.Element }): React.JSX.Element {
  return (
    <Card>
      <MessageCard
        title={copy({ de: 'Anmelden, um Duelle zu spielen', en: 'Sign in to duel', pl: 'Zaloguj się, aby grać w pojedynki' })}
        description={copy({ de: 'Gäste können die öffentliche Lobby und Rangliste ansehen. Melde dich an, um Duelle zu erstellen oder ihnen beizutreten.', en: 'Guests can browse the public lobby and leaderboard. Sign in to create or join duels.', pl: 'Goście mogą przeglądać publiczne lobby i ranking. Zaloguj się, aby tworzyć pojedynki lub do nich dołączać.' })}
      />
      {loginIntroCallToAction}
    </Card>
  );
}

export function DuelsLobbyView(props: DuelsLobbyViewProps): React.JSX.Element {
  const {
    copy,
    lobby,
    activeLearnerId,
    autoRefreshEnabled,
    autoRefreshChipLabel,
    canSendChatMessage,
    chat,
    chatActionError,
    chatDraft,
    chatRemainingChars,
    lobbyChatPreview,
    locale,
    onChatDraftChange,
    onOpenSession,
    onSendLobbyChat,
    onToggleAutoRefresh,
    renderJoinAction,
    renderSpectateAction,
    searchStatusLabel,
    searchStatusTone,
    loginIntroCallToAction,
  } = props;

  return (
    <KangurMobileScrollScreen contentContainerStyle={{ gap: 18, paddingHorizontal: 20, paddingVertical: 24 }} keyboardShouldPersistTaps='handled'>
      <View style={{ gap: 14 }}>
        <LinkButton href={HOME_ROUTE} label={copy({ de: 'Zurück', en: 'Back', pl: 'Wróć' })} tone='secondary' />
        <KangurMobileSectionTitle
          title={copy({ de: 'Duelle', en: 'Duels', pl: 'Pojedynki' })}
          subtitle={copy({ de: 'Von hier aus startest du schnelle Matches, öffnest öffentliche Herausforderungen und kehrst direkt zu aktiven Rivalen zurück.', en: 'From here you can start quick matches, open public challenges, and jump straight back to active rivals.', pl: 'Stąd uruchomisz szybkie mecze, otworzysz publiczne wyzwania i od razu wrócisz do aktywnych rywali.' })}
        />
      </View>

      {!lobby.isAuthenticated && !lobby.isLoadingAuth ? <GuestIntroCard copy={copy} loginIntroCallToAction={loginIntroCallToAction} /> : null}

      <DuelLobbyPlayPanel copy={copy} locale={locale} lobby={lobby} loginStartCallToAction={props.loginStartCallToAction} onOpenSession={onOpenSession} />
      <DuelLobbyRoomsPanel autoRefreshChipLabel={autoRefreshChipLabel} autoRefreshEnabled={autoRefreshEnabled} copy={copy} locale={locale} lobby={lobby} onToggleAutoRefresh={onToggleAutoRefresh} renderJoinAction={renderJoinAction} renderSpectateAction={renderSpectateAction} />
      <DuelLobbyChatPanel activeLearnerId={activeLearnerId} canSendChatMessage={canSendChatMessage} chat={chat} chatActionError={chatActionError} chatDraft={chatDraft} chatRemainingChars={chatRemainingChars} copy={copy} lobbyChatPreview={lobbyChatPreview} locale={locale} onChatDraftChange={onChatDraftChange} onSendLobbyChat={onSendLobbyChat} />
      <DuelLobbyPresenceSection copy={copy} locale={locale} lobby={lobby} />
      <DuelLobbySearchSection copy={copy} locale={locale} lobby={lobby} onOpenSession={onOpenSession} searchStatusLabel={searchStatusLabel} searchStatusTone={searchStatusTone} />
      <DuelLobbyRecentOpponentsSection copy={copy} locale={locale} lobby={lobby} onOpenSession={onOpenSession} />
      <DuelLobbyLeaderboardSection copy={copy} locale={locale} lobby={lobby} />
      <LessonCheckpointsCard context='lobby' />
      <LessonMasteryCard context='lobby' />
      <BadgesCard context='lobby' />
      <NextStepsCard context='lobby' />
    </KangurMobileScrollScreen>
  );
}

import type { Href } from 'expo-router';
import type { KangurDuelLeaderboardEntry, KangurDuelOpponentEntry } from '@kangur/contracts/kangur-duels';

export type UseKangurMobileLearnerDuelsSummaryResult = {
  actionError: string | null;
  createRematch: (opponentLearnerId: string) => Promise<string | null>;
  currentEntry: KangurDuelLeaderboardEntry | null;
  currentRank: number | null;
  error: string | null;
  isActionPending: boolean;
  isAuthenticated: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  opponents: KangurDuelOpponentEntry[];
  pendingOpponentLearnerId: string | null;
  refresh: () => Promise<void>;
};

export type SummaryIdentity = {
  learnerIdentity: string;
  activeLearnerId: string | null;
};

import { useState, useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import {
  MOBILE_DUEL_DEFAULT_DIFFICULTY,
  MOBILE_DUEL_DEFAULT_OPERATION,
  MOBILE_DUEL_DEFAULT_QUESTION_COUNT,
  MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
} from './mobileDuelDefaults';
import { toDuelsSummaryActionErrorMessage } from './useKangurMobileLearnerDuelsSummary.errors';
import type { DuelApiClient } from './useKangurMobileDuelsLobbyQueries';

export function useDuelsSummaryRematch(
  apiClient: DuelApiClient,
  queryKeyBase: { leaderboard: readonly unknown[]; opponents: readonly unknown[] },
) {
  const queryClient = useQueryClient();
  const { copy } = useKangurMobileI18n();
  const [actionError, setActionError] = useState<string | null>(null);
  const [isActionPending, setIsActionPending] = useState(false);
  const [pendingOpponentLearnerId, setPendingOpponentLearnerId] = useState<string | null>(null);

  const createRematch = useCallback(async (opponentLearnerId: string): Promise<string | null> => {
    setActionError(null);
    setIsActionPending(true);
    setPendingOpponentLearnerId(opponentLearnerId);
    try {
      const resp = await apiClient.createDuel({
        difficulty: MOBILE_DUEL_DEFAULT_DIFFICULTY,
        mode: 'challenge',
        operation: MOBILE_DUEL_DEFAULT_OPERATION,
        opponentLearnerId,
        questionCount: MOBILE_DUEL_DEFAULT_QUESTION_COUNT,
        timePerQuestionSec: MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
        visibility: 'private',
      }, { cache: 'no-store' });

      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeyBase.leaderboard }),
        queryClient.invalidateQueries({ queryKey: queryKeyBase.opponents }),
      ]);

      return resp.session?.id ?? null;
    } catch (err: unknown) {
      setActionError(toDuelsSummaryActionErrorMessage(err, copy));
      return null;
    } finally {
      setIsActionPending(false);
      setPendingOpponentLearnerId(null);
    }
  }, [apiClient, queryClient, queryKeyBase, copy]);

  return { actionError, isActionPending, pendingOpponentLearnerId, createRematch };
}

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];

export const toDuelsSummaryErrorMessage = (
  error: unknown,
  copy: DuelCopy,
): string | null => {
  if (error === null || error === undefined) {
    return null;
  }

  if (typeof error === 'object' && 'status' in error) {
    const status = (error as { status?: number }).status;

    if (status === 401) {
      return copy({
        de: 'Melde dich an, um Duellstatistiken zu laden.',
        en: 'Sign in to load duel stats.',
        pl: 'Zaloguj się, aby pobrać statystyki pojedynków.',
      });
    }
  }

  if (!(error instanceof Error)) {
    return copy({
      de: 'Die Duellstatistiken konnten nicht geladen werden.',
      en: 'Could not load duel stats.',
      pl: 'Nie udało się pobrać statystyk pojedynków.',
    });
  }

  const message = error.message.trim();
  if (message === '') {
    return copy({
      de: 'Die Duellstatistiken konnten nicht geladen werden.',
      en: 'Could not load duel stats.',
      pl: 'Nie udało się pobrać statystyk pojedynków.',
    });
  }

  const normalized = message.toLowerCase();
  if (normalized === 'failed to fetch' || normalized.includes('networkerror')) {
    return copy({
      de: 'Die Duellstatistiken konnten nicht geladen werden.',
      en: 'Could not load duel stats.',
      pl: 'Nie udało się pobrać statystyk pojedynków.',
    });
  }

  return message;
};

export const toDuelsSummaryActionErrorMessage = (
  error: unknown,
  copy: DuelCopy,
): string => {
  if (typeof error === 'object' && error !== null && 'status' in error) {
    const status = (error as { status?: number }).status;

    if (status === 401) {
      return copy({
        de: 'Melde dich an, um ein privates Rückspiel zu senden.',
        en: 'Sign in to send a private rematch.',
        pl: 'Zaloguj się, aby wysłać prywatny rewanż.',
      });
    }
  }

  if (!(error instanceof Error)) {
    return copy({
      de: 'Das private Rückspiel konnte nicht erstellt werden.',
      en: 'Could not create the private rematch.',
      pl: 'Nie udało się utworzyć prywatnego rewanżu.',
    });
  }

  const message = error.message.trim();
  if (message === '') {
    return copy({
      de: 'Das private Rückspiel konnte nicht erstellt werden.',
      en: 'Could not create the private rematch.',
      pl: 'Nie udało się utworzyć prywatnego rewanżu.',
    });
  }

  const normalized = message.toLowerCase();
  if (normalized === 'failed to fetch' || normalized.includes('networkerror')) {
    return copy({
      de: 'Das private Rückspiel konnte nicht erstellt werden.',
      en: 'Could not create the private rematch.',
      pl: 'Nie udało się utworzyć prywatnego rewanżu.',
    });
  }

  return message;
};

import type { KangurDuelLeaderboardEntry } from '@kangur/contracts/kangur-duels';
import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { useKangurMobileHomeDuelsLeaderboard } from '../home/useKangurMobileHomeDuelsLeaderboard';
import { toDuelsSummaryErrorMessage } from './useKangurMobileLearnerDuelsSummary.errors';
import { useSummaryIdentity } from './useDuelsSummaryIdentity';
import { useDuelsSummaryRematch } from './useDuelsSummaryRematch';
import type { UseKangurMobileLearnerDuelsSummaryResult } from './duels-summary-types';
import type { DuelApiClient } from './useKangurMobileDuelsLobbyQueries';

function resolveLearnerRank(
  activeLearnerId: string | null, 
  entries: KangurDuelLeaderboardEntry[]
): { rank: number | null; entry: KangurDuelLeaderboardEntry | null } {
  const index = activeLearnerId !== null ? entries.findIndex((e) => e.learnerId === activeLearnerId) : -1;
  return { rank: index >= 0 ? index + 1 : null, entry: index >= 0 ? (entries[index] ?? null) : null };
}

export const useKangurMobileLearnerDuelsSummary = ({
  leaderboardLimit,
  leaderboardLookbackDays,
  opponentsLimit,
}: {
  leaderboardLimit: number;
  leaderboardLookbackDays: number;
  opponentsLimit: number;
}): UseKangurMobileLearnerDuelsSummaryResult => {
  const { copy } = useKangurMobileI18n();
  const { apiBaseUrl, apiClient: rawApiClient } = useKangurMobileRuntime();
  const apiClient = rawApiClient as unknown as DuelApiClient;
  const { isLoadingAuth, session: authSession } = useKangurMobileAuth();
  const duelLeaderboard = useKangurMobileHomeDuelsLeaderboard();

  const { learnerIdentity, activeLearnerId } = useSummaryIdentity(authSession);
  const isAuthenticated = authSession.status === 'authenticated';
  const isRestoringAuth = isLoadingAuth && !isAuthenticated;

  const queryKeyBase = useMemo(
    () => ({
      leaderboard: ['kangur-mobile', 'duels-summary', 'leaderboard', apiBaseUrl, learnerIdentity, leaderboardLimit, leaderboardLookbackDays] as const,
      opponents: ['kangur-mobile', 'duels-summary', 'opponents', apiBaseUrl, learnerIdentity, opponentsLimit] as const,
    }),
    [apiBaseUrl, learnerIdentity, leaderboardLimit, leaderboardLookbackDays, opponentsLimit],
  );

  const leaderboardQuery = useQuery({
    enabled: isAuthenticated,
    queryKey: queryKeyBase.leaderboard,
    queryFn: async () => apiClient.getDuelLeaderboard({ limit: leaderboardLimit, lookbackDays: leaderboardLookbackDays }, { cache: 'no-store' }),
    staleTime: 30_000,
  });

  const opponentsQuery = useQuery({
    enabled: isAuthenticated,
    queryKey: queryKeyBase.opponents,
    queryFn: async () => apiClient.listDuelOpponents({ limit: opponentsLimit }, { cache: 'no-store' }),
    staleTime: 30_000,
  });

  const { rank: currentRank, entry: currentEntry } = resolveLearnerRank(activeLearnerId, leaderboardQuery.data?.entries ?? []);

// Helper to avoid unsafe call/assignment
function resolveOpponents(data: any, opponentsLimit: number) {
  const rawEntries = (data?.entries ?? []) as KangurDuelLeaderboardEntry[];
  return [...rawEntries]
    .sort((l, r) => Date.parse(r.lastPlayedAt) - Date.parse(l.lastPlayedAt))
    .slice(0, opponentsLimit);
}

// ... existing code ...

  const opponents = useMemo(() => resolveOpponents(opponentsQuery.data, opponentsLimit), [opponentsLimit, opponentsQuery.data]);

  const { actionError, isActionPending, pendingOpponentLearnerId, createRematch } = useDuelsSummaryRematch(apiClient, queryKeyBase);

  return {
    actionError,
    createRematch,
    currentEntry,
    currentRank,
    error: toDuelsSummaryErrorMessage(opponentsQuery.error, copy) ?? toDuelsSummaryErrorMessage(leaderboardQuery.error, copy),
    isActionPending,
    isAuthenticated,
    isLoading: isRestoringAuth || leaderboardQuery.isLoading || opponentsQuery.isLoading,
    isRestoringAuth,
    opponents,
    pendingOpponentLearnerId,
    refresh: async (): Promise<void> => {
      await Promise.all([leaderboardQuery.refetch(), opponentsQuery.refetch()]);
    },
  };
};
